mapper.select:
SELECT history.user_id, history.username, history.item_id, history.title, history.artist_name, history.album_name, history.genre_code, history.cover_url, history.preview_url, history.last_listen_time, history.play_count, history.complete_play_count, history.played_duration_seconds, history.max_watch_ratio FROM ( SELECT i.user_id, u.external_user_no AS username, i.item_id, it.title, it.artist_name, it.album_name, it.genre_code, m.cover_url, m.preview_url, MAX(i.event_time) AS last_listen_time, SUM(CASE WHEN i.event_type = 'play_start' THEN 1 ELSE 0 END) AS play_count, SUM(CASE WHEN i.event_type = 'play_complete' THEN 1 ELSE 0 END) AS complete_play_count, COALESCE(SUM(CASE WHEN i.play_duration_sec IS NULL THEN 0 ELSE i.play_duration_sec END), 0) AS played_duration_seconds, COALESCE(MAX(i.watch_ratio), 0) AS max_watch_ratio FROM interactions i JOIN users u ON u.user_id = i.user_id JOIN items it ON it.item_id = i.item_id LEFT JOIN item_media m ON m.item_id = i.item_id WHERE i.event_type IN ('play_start', 'play_stop', 'play_complete')
AND i.user_id = #{userId}
GROUP BY i.user_id, u.external_user_no, i.item_id, it.title, it.artist_name, it.album_name, it.genre_code, m.cover_url, m.preview_url ) history ORDER BY history.last_listen_time DESC, history.user_id DESC, history.item_id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM ( SELECT 1 FROM interactions i WHERE i.event_type IN ('play_start', 'play_stop', 'play_complete')
AND i.user_id = #{userId}
GROUP BY i.user_id, i.item_id ) history_count

