INSERT INTO interactions (
    request_id, trace_id, user_id, item_id, event_type, event_time,
    play_duration_sec, watch_ratio, device_type, channel, position_no, context_json
) VALUES (
    #{requestId}, #{traceId}, #{userId}, #{itemId}, #{eventType}, #{eventTime},
    #{playDurationSec}, #{watchRatio}, #{deviceType}, #{channel}, #{positionNo}, #{contextJson}
)
